import React, { useEffect, useState } from "react";
import { Navigate } from "react-router-dom";
import { getUser, setUser } from "../api/storage";
import client from "../api/client";

const RequireAdmin = ({ children }) => {
  const user = getUser();
  const [isVerified, setIsVerified] = useState(false);
  const [loading, setLoading] = useState(true);
  const [redirectToLogin, setRedirectToLogin] = useState(false);
  const [redirectToDashboard, setRedirectToDashboard] = useState(false);

  useEffect(() => {
    verifyAdminRole();
  }, []);

  const verifyAdminRole = async () => {
    try {
      // If no user in localStorage, redirect to login
      if (!user) {
        setRedirectToLogin(true);
        setLoading(false);
        return;
      }

      // Verify user role from backend
      const { data } = await client.get("/auth/profile/");
      console.log("[RequireAdmin] Profile data:", data);
      
      // Update stored user with fresh data from API
      setUser(data);

      // Check if user is admin
      if (data.is_staff || data.role === 'admin') {
        setIsVerified(true);
      } else {
        console.warn("[RequireAdmin] User is not admin, role:", data.role);
        setRedirectToDashboard(true);
      }
    } catch (error) {
      console.error("[RequireAdmin] Failed to verify role:", error);
      // If API call fails but user is in localStorage with admin role, allow access
      if (user && (user.is_staff || user.role === 'admin')) {
        setIsVerified(true);
      } else {
        setRedirectToLogin(true);
      }
    } finally {
      setLoading(false);
    }
  };

  // Show loading state while verifying
  if (loading) {
    return (
      <div style={{
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        height: '100vh',
        background: '#f5f5f5'
      }}>
        <div style={{ textAlign: 'center' }}>
          <div style={{ fontSize: '32px', marginBottom: '16px' }}>⏳</div>
          <p style={{ color: '#666' }}>Verifying admin access...</p>
        </div>
      </div>
    );
  }

  // Redirect to login if not authenticated
  if (redirectToLogin) {
    return <Navigate to="/login" replace />;
  }

  // Redirect to dashboard if not admin
  if (redirectToDashboard) {
    return <Navigate to="/dashboard" replace />;
  }

  // User is verified admin, allow access
  if (isVerified) {
    return children;
  }

  return null;
};

export default RequireAdmin;
